def generer_rapport_final(evenements, alertes, chemin="rapport_soc.json"):
    """Génère le rapport final de l'analyse SOC."""
    critiques = [a for a in alertes if a["severite"] == "CRITIQUE"]
    ips_uniques = {e.get("ip") for e in evenements if e.get("ip")}

    rapport = {
        "metadata": {
            "timestamp": datetime.now().isoformat(),
            "outil": "SOC Analyzer v1.0",
            "analyste": os.getenv("USERNAME", "inconnu")
        },
        "resume": {
            "evenements_analyses": len(evenements),
            "alertes_totales": len(alertes),
            "alertes_critiques": len(critiques),
            "ips_uniques": len(ips_uniques),
            "ioc_matches": sum(1 for e in evenements if e.get("ioc_match"))
        },
        "alertes": alertes,
        "top_ips": [
            {"ip": ip, "count": count}
            for ip, count in Counter(e.get("ip") for e in evenements if e.get("ip")).most_common(5)
        ]
    }

    with open(chemin, "w", encoding="utf-8") as f:
        json.dump(rapport, f, indent=2, ensure_ascii=False)

    print(f"\nRapport sauvegardé : {chemin}")
    print(f"Résumé :")
    for cle, val in rapport["resume"].items():
        print(f"  {cle:<30} : {val}")

    # Score de sévérité global
    score_global = len(critiques) * 20 + len([a for a in alertes if a["severite"] == "HAUTE"]) * 10
    niveau = "CRITIQUE" if score_global >= 40 else "HAUTE" if score_global >= 20 else "MOYENNE"
    print(f"\nNiveau de menace global : {niveau} (score={score_global})")
    return rapport

rapport_final = generer_rapport_final(evenements, alertes)
